local LxBaseAdapter = require("LApp.adapter.LxBaseAdapter")
---@class LxMainAdapter:LxBaseAdapter
local LxMainAdapter = classX("LxMainAdapter", LxBaseAdapter)

local _MAP_ROOT_NAME = "resource"
local _MAP_FORMATION_NAME = "FormationResource"
local _MAP_CLASS_ROOT = "LApp.Scene.Map."
local _MAP_FADE_NAME = "MapFade"

function LxMainAdapter:Initialize()
    LxBaseAdapter.Initialize(self)
    self._adapterName = LevelNames.Main

    self:EnableCameraAdapt(true)

    ---@type LDisplayPrefab
    self._loadedDp = {}

    self._dicMap = {}

    ---@type LMapBase
    self._curMap = nil

    self._transitMap = nil

    self._mapRootTrans = nil
    self._transitTimer = nil

    ---@type LFormationGrid
    self._formationGrid = nil

    ---@type LxHudResGetter
    self._hudGetter = nil
end


function LxMainAdapter:Dispose()
    self:ClearAdapter()
    LxBaseAdapter.Dispose(self)
end

function LxMainAdapter:OnEnterLevel(scene, loadMode, mapGo)
    LxBaseAdapter.OnEnterLevel(self,scene, loadMode, mapGo)

    self._curMap:EnterMap()

    self:OnSceneEnterFinished()
end

function LxMainAdapter:OnWillLeaveLevel()
    self:ClearAdapter()

    LxBaseAdapter.OnWillLeaveLevel(self)
end


function LxMainAdapter:OnLeaveLevel()

end

function LxMainAdapter:IsCheckRemainScene()
    return true
end

function LxMainAdapter:ClearAdapter()
    if self._isDisposed then return end

    for k, v in ipairs(self._loadedDp) do
        v:Destroy()
    end

    self._loadedDp = {}

    if self._hudGetter then
        self._hudGetter:Dispose()
        self._hudGetter = nil
    end

    self:StopTransitTimer()
    for k, v in pairs(self._dicMap) do
        v:Destroy()
    end
    self._dicMap = {}

    if self._formationGrid then
        self._formationGrid:Destroy()
        self._formationGrid = nil
    end

    self:StopSysObserver()
end

function LxMainAdapter:OnLevelLoaded()
    LxBaseAdapter.OnLevelLoaded(self)
    self:OnSceneLoaded()
end

---@param batchTask LxPreloadTask
function LxMainAdapter:AfterLevelLoaded(batchTask)
    batchTask:AddBatchTask("prepareMain", "prepareMain", self.PrepareScene, self)
    batchTask:AddBatchTask("PreLoadHud", "PreLoadHud", self.PreLoadHud, self)
end

function LxMainAdapter:OnSceneLoaded()
    if(gModelBlockMiniGame:GetWXBSCameraFlag())then
        local _sceneCamera = gLGameScene:GetCurrentSceneCamera()
        _sceneCamera.orthographicSize = LUtil.GetCameraSize()
        gModelBlockMiniGame:SetWXBSCameraFlag(false)
    end
    
    self:InitMainSceneNode()
    ---本地通知初始化
    LxAlarmHelper.InitAlarm()

    if gModelGM:IsGMOpen() then
        local gmShow = GameTable.GameServerConfigRef["gmShow"]
        if not gmShow or gmShow == 0 then
            GF.OpenWndDebug("UIGMnBtn")
        end
    end

    GF.OpenUIGue("UIGue") --预先打开指引界面，防止越过指引点击

    local bCheckResDownload = true
    if gLGameLogin:GetPlayCartoon() then
        bCheckResDownload = false
    end

    local startCtrl = self:GetStartCtrl()
    local map = startCtrl:OnSceneLoaded()
    
    self._curMap = self:AddNewMap(map)
    self._curMap:ResetMap()

    gModelGeneral:SetHasEnteredCityMap()

    -- 数数打点，进入游戏界面
    local server_id = gLGameLogin:GetServerId() or ""
    local ref_id = gLGameLogin:GetPlayerId() or "0"
    local name = gLGameLogin:GetPlayerName() or ""
    gLxTKData:StepGameUI(server_id, ref_id, name)
    -- 初始化TCP打点记录
    local loginServer = gLGameLogin:GetLoginServer()
    gLxTKData:InitTKStepDatas(loginServer)

    --gModelDreamFountain:OnLoginNotifyReq()
    gLSdkImpl:CallMethod(LSdkMethod.OnFirstEnterCity)

    if gLSdkImpl then
        if gLSdkImpl:CallMethod(LSdkMethod.IsLaunchFromSideBar) or 
                gLSdkImpl:CallMethod(LSdkMethod.IsLaunchFromDesktop) then
            gModelPlayer:OnAuthOnetimeStateReq(ModelPlayer.LAUNCHSIDEBAR)
        end
    end
end

function LxMainAdapter:GetStartCtrl()
    if self._startCtrl then
        return self._startCtrl
    end
    local guideType = gModelGuide:GetGuideType()

    local ctrl = nil
    if guideType == 1 then
        ctrl = require("LApp.Scene.Ctrl.StartCtrlNewOne"):New(guideType)
    elseif guideType == 5 then
        ctrl = require("LApp.Scene.Ctrl.StartCtrlFour"):New(guideType)
    elseif guideType == 6 then
        ctrl = require("LApp.Scene.Ctrl.StartCtrlGuideStory"):New(guideType)
    end

    self._startCtrl = ctrl
    return ctrl
end

function LxMainAdapter:PrepareScene(actionOk, actionObj)
    self._preLoadCount = 0
    self:InitPrefabLoad(function(maxCount)
        self._preLoadCount = self._preLoadCount + 1
        if self._preLoadCount < maxCount then return end
        self._curMap:StartLoadMap(function()
            actionOk(actionObj)
        end)
    end)
end

function LxMainAdapter:PreLoadHud(actionOk, actionObj)
    if self._hudGetter then
        self._hudGetter:Dispose()
    end

    self._hudGetter = require("LApp.Scene.LxHudResGetter"):New()
    self._hudGetter:PrepareHud(actionOk, actionObj)
end


function LxMainAdapter:StopDelayHideUIGrayTimer()
    if self._delayHideUIGrayTimer then
        LxTimer.DelayTimeStop(self._delayHideUIGrayTimer)
        self._delayHideUIGrayTimer = nil
    end
end
function LxMainAdapter:DelayHideUIGray()
    self:StopDelayHideUIGrayTimer()
    self._delayHideUIGrayTimer = LxTimer.DelayTimeCall(function()
        self._delayHideUIGrayTimer = nil
        gLGamePostProcess:HideUIGray(0.5)
    end, 0.5)
end

function LxMainAdapter:OnSceneEnterFinished()
    GF.CloseUIBtBackground()

    gModelGameHelper:RefreshGameSpeed()

    self:OpenSysShotObserver()

    local toBattle = false
    if gModelBattle then
        toBattle = gModelBattle:CheckCacheOfflineCombat()
    end

    local startCtrl = self:GetStartCtrl()
    startCtrl:OnSceneEnterFinished(toBattle)

    if gModelEndles then
        gModelEndles:StartSelectTimer()
    end

    gModelGuide:OnEnterCityMap()

    gLGameLogin:StartGameTickTimer()
end

function LxMainAdapter:OnCameraAdapt()
    LxBaseAdapter.OnCameraAdapt(self)

    if self._curMap then
        self._curMap:OnCameraAdapt()
    end
end

function LxMainAdapter:ShakeMainScene(time,intensityX,intensityY)
    if self._curMap then
        self._curMap:Shake(time,intensityX,intensityY)
    end
end

