function LxMainAdapter:OnSysScreenShot()
    if not gModelFunctionOpen:CheckIsOpened(18000020) then
        return
    end
    local func = function()
        GF.OpenWndTop("UIScreenShotSpread")
    end
    local firstScreenShot = toboolean(LPlayerPrefs.firstScreenShot)
    if firstScreenShot then
        LPlayerPrefs.SetFirstScreenShot(tostring(not firstScreenShot))
        gModelGeneral:OpenUIOrdinTips({refId = 120005,func = func})
    else
        func()
    end
end

function LxMainAdapter:OpenSysShotObserver()
    self:AddEventHandler(EventNames.SYS_SCREEN_SHOT, function ()
        self:OnSysScreenShot()
    end)

    if not gLSdkImpl:CallMethod(LSdkMethod.IsSupportShareChannel,LShareConst.MADFUN_SYSTEM) then
        return
    end

    local isOpen = toboolean(LPlayerPrefs.screenShare)
    if not LNativeHelper.CheckPermissionForObserverScreenShot() or not gLGameLogin:IsOpenScreenShotShare() then
        isOpen = false
    end
    LNativeHelper.CallMethod(LNativeMethod.DoSysShotWatch, isOpen)
end

function LxMainAdapter:StopSysObserver()
    LNativeHelper.CallMethod(LNativeMethod.DoSysShotWatch, false)
end

-----------------------------------------------------------------
function LxMainAdapter:InitMainSceneNode()
    local sceneMainRoot = self:GetSceneMainRoot()
    self._mapRootTrans = CS.FindTrans(sceneMainRoot, _MAP_ROOT_NAME)
end

function LxMainAdapter:InitPrefabLoad(callBack)
    local sceneMainRoot = self:GetSceneMainRoot()

    local maxLoadPrefab = 2
    --战斗阵型节点

    local mapFormationResource = CS.FindTrans(sceneMainRoot, _MAP_FORMATION_NAME)
    if not mapFormationResource then
        local dp = LDisplayPrefab:New()
        table.insert(self._loadedDp, dp)
        dp:CreatePrefab(sceneMainRoot,"Map/Prefabs", _MAP_FORMATION_NAME)
        dp:SetLoadedFunction(function (prefabDp)
            local cloneTrans = prefabDp:GetDisplayTrans()
            if cloneTrans then
                self._mapFormationResource = cloneTrans
                CS.ShowObject(cloneTrans, false)

                if callBack ~= nil then
                    callBack(maxLoadPrefab)
                end
            end
        end)
        dp:StartLoad()
    else
        self._mapFormationResource = mapFormationResource
        CS.ShowObject(mapFormationResource, false)

        if callBack ~= nil then
            callBack(maxLoadPrefab)
        end
    end

    local mapFade = CS.FindTrans(sceneMainRoot,_MAP_FADE_NAME)
    if not mapFade then
        local dp = LDisplayPrefab:New()
        table.insert(self._loadedDp, dp)
        dp:CreatePrefab(sceneMainRoot,"Map/Prefabs", _MAP_FADE_NAME)
        dp:SetLoadedFunction(function (prefabDp)
            local cloneTrans = prefabDp:GetDisplayTrans()
            if cloneTrans then
                self._mapFade = cloneTrans
                CS.ShowObject(cloneTrans, false)
                if callBack ~= nil then
                    callBack(maxLoadPrefab)
                end
            end
        end)
        dp:StartLoad()
    else
        self._mapFade = mapFade
        CS.ShowObject(mapFade, false)
        if callBack ~= nil then
            callBack(maxLoadPrefab)
        end
    end
end

function LxMainAdapter:GetFormationGrid(isBattleShow)
    local formationGrid = self._formationGrid
    if not formationGrid then
        formationGrid = LxRequire("LApp.Scene.Object.LFormationGrid"):New()
        self._formationGrid = formationGrid
        formationGrid:InitFormationGrid(self._mapFormationResource,isBattleShow)
    end
    return formationGrid
end

-----------------------------------------------------------------
function LxMainAdapter:AddNewMap(mapClassName)
    local mapClass = LxRequire(_MAP_CLASS_ROOT .. mapClassName)
    local mapInst = mapClass:New()
    mapInst:Create(self, self._mapRootTrans)
    self._dicMap[mapInst:GetMapClassName()] = mapInst
    return mapInst
end

-----------------------------------------------------------------
function LxMainAdapter:CheckClearMap(dicIgnore)
    local clearList = {}
    local bHave = false
    local time = GetTimestamp()
    for k,v in pairs(self._dicMap) do
        if v:IsCheckClear() and  not dicIgnore[k] and v:IsExistTimeOut(time) then
            table.insert(clearList, v)
            bHave = true
        end
    end
    if bHave then
        table.sort(clearList, function (mA, mB)
            return mA:GetLastExistTime() < mB:GetLastExistTime()
        end)
        local map = clearList[1]
        self._dicMap[map:GetMapClassName()] = nil
        map:Destroy()
    end
end

