function LxMainAdapter:ChangeMap(className, isTransit , argList)
    local oldMap = self._curMap
    if(oldMap and oldMap:IsLoading()) then
        print("cur map is loading " .. oldMap:GetMapName())
        return false
    end

    local bCheckPop = self:RefreshPlayModule(className,argList)

    local fromMapClsName = oldMap:GetMapClassName()
    local bSameMap = oldMap:IsSameMap(className)

    if bSameMap and not oldMap:CheckNeedChange(argList) then
        if bCheckPop then
            gLGameUI:CheckPopWnd()
        end
        return false
    end

    local map = self._dicMap[className]
    local oldMapName
    if not map then
        map = self:AddNewMap(className)
        self._curMap = map
    else
        oldMapName = map:GetMapName()
    end

    self._curMap = map

    if map:IsBlurMap(argList) then
        gLGamePostProcess:SaveRenderTexture(1) --提前截屏
    end

    local clearOldMap = function()
        --gprint("清理旧地图资源")
        ---清理旧地图资源
        if oldMap then
            oldMap:ExitMap()
        end

        self:OnChangeMapClear(fromMapClsName, className)

        --清理很久没进入的地图
        self:CheckClearMap({ [className] = true, [fromMapClsName] = true })

    end

    local isWebGL = CS.IsWebGL()
    if not isWebGL then
        clearOldMap()
    end

    ---同样的地图不需要先关闭再显示
    if bSameMap then
        oldMap = nil
    end

    map:ResetMap(argList)

    ---停止旧的过渡
    self:StopTransitTimer()
    local transitMap = self._transitMap
    self._transitMap = nil

    ---过渡完成
    if not transitMap then
        transitMap = oldMap
    end


    local toMapClsName = map:GetMapClassName()

    local onLoadedFunc = function()
        if isWebGL then
            clearOldMap()

            --if LResRelease then
            --    LResRelease.OnMapChanged(fromMapClsName, toMapClsName)
            --end
            LxResUtil.RunUnusedAssetUnload()
        end

        if(transitMap) then
            transitMap:SetMapVisible(false)
        end
        self._transitMap = nil
        map:SetMapVisible(true)
        map:EnterMap()

        if map:IsBlurMap(argList) then
            map:ResetBlurMap()
        end

    end

    if not isWebGL then
        --if LResRelease then
        --    LResRelease.OnMapChanged(fromMapClsName, toMapClsName)
        --end
        LxResUtil.RunUnusedAssetUnload()
    end

    local tryLoadedFunc = function()
        if isTransit and transitMap and transitMap ~= map then
            self._transitMap = transitMap
            self:StartTransitTimer(onLoadedFunc)
        else
            onLoadedFunc()
        end
    end

    ---两次一样的预制体不重新加载，直接显示
    if map:GetMapName() == oldMapName then
        if map:IsMapReady() then
            tryLoadedFunc()
        end
        return true
    end

    if isTransit and transitMap and transitMap ~= map then
        map:SetMapVisible(false)
    end

    if LOG_INFO_ENABLED then
        print("change map ".. map:GetMapName())
    end

    if map:IsWaitZhuanchang() then
        local hideTime = map:GetWaitZhuanchangTime()
        GF.CloseWndByName("UIWaitZC")
        GF.OpenWndWait("UIWaitZC", {
            hideEndFunc=function()
                map:StartLoadMap(onLoadedFunc)
            end,
            hideTime = hideTime
        })
        return true
    end

    map:StartLoadMap(tryLoadedFunc)

    if bCheckPop then
        gLGameUI:CheckPopWnd()
    end


    return true
end

function LxMainAdapter:RefreshPlayModule(mapName,argList)
    local playModule = LPlayModuleConst.NONE
    if mapName == "LBattleMap" then
        local combatType =nil
        local isOnlySet = argList.isOnlySet
        if isOnlySet then
            combatType = argList.para.setTargetType
        else
            combatType =argList.extraData.combatType
        end

        playModule = gLFightManager:GetPlayModuleByCombat(combatType)
    elseif mapName == "LInvasionMap" then
        playModule = LPlayModuleConst.INVASION
        --elseif mapName == "LTimeCorridorMap" then
        --    playModule = gModelTimeCorridor:GetBelongModule(argList.refId)
    elseif mapName == "LDreamTripMap" or mapName == "LFastDreamTripMap" then
        playModule = LPlayModuleConst.TRAVEL
    elseif mapName == "LWonderlandMap" or mapName == "LWonderlordMap" then
        playModule = LPlayModuleConst.WONDERLAND
    end

    if playModule == self:GetPlayModule() then
        return
    end

    self._playModule = playModule
    return true
end

function LxMainAdapter:GetPlayModule()
    return self._playModule or LPlayModuleConst.NONE
end


function LxMainAdapter:OnChangeMapClear(oldMap,newMap)
    if oldMap == newMap then
        return
    end

    if oldMap == "LWonderlandMap" and newMap ~= "LWonderlordMap" then
        GF.CloseWndByName("UIEden")
    end

    if not (newMap == "LFightIdleMap" or newMap == "LGuideStoryMap") then
        GF.CloseWndByName("UIMinFight")
    end

    -- 【C宠物系统】删掉宠物系统相关
    -- if oldMap == "LPetBattleMap" and newMap ~= "LPetBattleMap" then
    --     GF.CloseWndByName("WndPetFight")
    -- end

end

function LxMainAdapter:StartTransitTimer(func)
    self:StopTransitTimer()
    self._transitTimer = LXFW.LxTimer.DelayTimeCall(func,0.3)
end

function LxMainAdapter:StopTransitTimer()
    if self._transitTimer then
        LXFW.LxTimer.DelayTimeStop(self._transitTimer)
        self._transitTimer = nil
    end
end

function LxMainAdapter:GetMapRoot()
    return self._mapRootTrans
end

function LxMainAdapter:GetCurMapTran()
    if self._curMap then
        return self._curMap:GetMapTrans()
    end
end

function LxMainAdapter:GetCurMap()
    return self._curMap
end

function LxMainAdapter:IsCheckRemainScene()
    return true
end

function LxMainAdapter:IsCustomAxis()
    return true
end

function LxMainAdapter:GetMapFade()
    return self._mapFade
end

function LxMainAdapter:GetHudAssetObject(name)
    if self._hudGetter then
        return self._hudGetter:GetHudByName(name)
    end
end

function LxMainAdapter:OnApplicationPause(isPause)
    if self._curMap and self._curMap.OnApplicationPause then
        self._curMap:OnApplicationPause(isPause)
    end
end


return LxMainAdapter